SELECT
    p.*,
    p.planned_recruit - COALESCE(
        (SELECT COUNT(*) FROM student_internship_status sis
         WHERE sis.position_id = p.id AND sis.status IN (1, 2)), 0
    ) AS remaining_quota,
    COALESCE(
        (SELECT COUNT(*) FROM student_internship_status sis
         WHERE sis.position_id = p.id AND sis.status IN (1, 2)), 0
    ) AS recruited_count
FROM position p


        p.company_id = #{companyId}


        and p.position_name like concat('%', #{positionName}, '%')


        and p.department = #{department}


        and p.status = #{status}


order by p.create_time desc

mapper.update:
UPDATE position p
SET
    p.recruited_count = (
        SELECT COUNT(*)
        FROM student_internship_status sis
        WHERE sis.position_id = #{positionId}
        AND sis.status IN (1, 2)
    ),
    p.remaining_quota = p.planned_recruit - (
        SELECT COUNT(*)
        FROM student_internship_status sis
        WHERE sis.position_id = #{positionId}
        AND sis.status IN (1, 2)
    ),
    p.update_time = NOW()
WHERE p.id = #{positionId}
